// Extract caller speech and call information from Twilio webhook
const item = $input.first().json;

// Extract SpeechResult from Twilio webhook query parameters
const callerSpeech = item.query?.SpeechResult || '';

// Extract CallSid
const callSid = item.query?.CallSid || '';

// Return object with callSid, callerSpeech, and timestamp
return {
  json: {
    callSid: callSid,
    callerSpeech: callerSpeech,
    timestamp: new Date().toISOString()
  }
};

// Build TwiML XML response with <Gather> for speech input
const aiResponse = $('Generate AI Response').first().json.message || 'Hello, how can I help you today?';
const webhookUrl = $('Inbound Call (Per-Segment)').first().json.webhookUrl;

// Build TwiML XML
const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Gather input="speech" language="en-US" timeout="3" action="${webhookUrl}">
    <Say>${aiResponse}</Say>
  </Gather>
  <Say>I didn't hear anything. Goodbye!</Say>
</Response>`;

return {
  json: {
    twiml: twiml,
    contentType: 'text/xml'
  }
};

// Parse conversation history from Redis and build context for AI
const item = $input.item.json;

// Get the conversation history from Redis (if exists)
let conversationHistory = [];
try {
  if (item.conversationHistory && typeof item.conversationHistory === 'string') {
    conversationHistory = JSON.parse(item.conversationHistory);
  } else if (Array.isArray(item.conversationHistory)) {
    conversationHistory = item.conversationHistory;
  }
} catch (error) {
  console.log('No existing conversation history or parse error:', error.message);
  conversationHistory = [];
}

// Get the latest caller speech from the previous node
const latestSpeech = item.callerSpeech || item.speech || '';

// Append the latest caller speech to the conversation
if (latestSpeech && latestSpeech.trim() !== '') {
  conversationHistory.push({
    role: 'user',
    content: latestSpeech,
    timestamp: new Date().toISOString()
  });
}

// Build a formatted conversation context string for the AI
let conversationContext = '';
if (conversationHistory.length > 0) {
  conversationContext = conversationHistory.map(turn => {
    const role = turn.role === 'user' ? 'Caller' : 'AI';
    return `${role}: ${turn.content}`;
  }).join('\n\n');
}

// Return both the conversation array and formatted context
return {
  conversationHistory: conversationHistory,
  conversationArray: conversationHistory,
  conversationContext: conversationContext,
  turnCount: conversationHistory.length,
  latestUserMessage: latestSpeech,
  callId: item.callId || item.CallSid || 'unknown',
  ...item
};

// Parse AI-extracted lead data and format for intake flow
const item = $input.item.json;

// Get the extracted lead data from the previous AI node
const extractedData = $('Extract Lead Data from Transcript').first().json;

// Get call metadata from the webhook
const callData = $('Call Ended (StatusCallback)').first().json;

// Format the lead object for intake flow
const leadData = {
  name: extractedData.name || extractedData.fullName || '',
  email: extractedData.email || '',
  phone: extractedData.phone || extractedData.phoneNumber || callData.From || '',
  reason: extractedData.reason || extractedData.inquiry || extractedData.purpose || 'Phone inquiry',
  source: 'ai-receptionist',
  callSid: callData.CallSid || callData.callSid || '',
  transcript: callData.transcript || callData.TranscriptionText || extractedData.transcript || '',
  metadata: {
    callDuration: callData.CallDuration || '',
    callStatus: callData.CallStatus || '',
    extractedAt: new Date().toISOString(),
    rawExtraction: extractedData
  }
};

return leadData;

// Append AI response to conversation history array
const item = $input.first().json;

// Get the conversation history from Build Conversation Context node
let conversationArray = [];
try {
  const contextData = $('Build Conversation Context').first().json;
  if (contextData.conversationArray && Array.isArray(contextData.conversationArray)) {
    conversationArray = contextData.conversationArray;
  } else if (contextData.conversationHistory && Array.isArray(contextData.conversationHistory)) {
    conversationArray = contextData.conversationHistory;
  }
} catch (error) {
  console.log('Error retrieving conversation history:', error.message);
  conversationArray = [];
}

// Get the AI response from the current item
const aiResponse = item.message || item.response || item.text || '';

// Append the AI response to the conversation array
if (aiResponse && aiResponse.trim() !== '') {
  conversationArray.push({
    role: 'assistant',
    content: aiResponse,
    timestamp: new Date().toISOString()
  });
}

// Return the updated conversation array
return {
  conversationArray: conversationArray,
  conversationHistory: conversationArray,
  turnCount: conversationArray.length,
  latestAiMessage: aiResponse,
  ...item
};

// Merge conversation history from Redis with call metadata from webhook
const callMetadata = $('Call Ended (StatusCallback)').first().json;
const conversationData = $('Retrieve Full Conversation (Call End)').first().json;

// Parse conversation history from Redis (stored as JSON string)
let conversationHistory = [];
try {
  if (conversationData.conversationHistory && typeof conversationData.conversationHistory === 'string') {
    conversationHistory = JSON.parse(conversationData.conversationHistory);
  } else if (Array.isArray(conversationData.conversationHistory)) {
    conversationHistory = conversationData.conversationHistory;
  }
} catch (error) {
  console.log('Error parsing conversation history:', error.message);
  conversationHistory = [];
}

// Format conversation history as readable transcript
let transcript = '';
if (conversationHistory.length > 0) {
  transcript = conversationHistory.map(turn => {
    const role = turn.role === 'user' ? 'Caller' : 'AI Receptionist';
    const timestamp = turn.timestamp ? new Date(turn.timestamp).toLocaleTimeString() : '';
    return `[${timestamp}] ${role}: ${turn.content}`;
  }).join('\n\n');
} else {
  transcript = 'No conversation history available';
}

// Merge everything together
return {
  callSid: callMetadata.CallSid || callMetadata.query?.CallSid || '',
  from: callMetadata.From || callMetadata.query?.From || '',
  to: callMetadata.To || callMetadata.query?.To || '',
  callStatus: callMetadata.CallStatus || callMetadata.query?.CallStatus || '',
  callDuration: callMetadata.CallDuration || callMetadata.query?.CallDuration || '',
  recordingUrl: callMetadata.RecordingUrl || callMetadata.query?.RecordingUrl || '',
  conversationHistory: conversationHistory,
  transcript: transcript,
  turnCount: conversationHistory.length,
  timestamp: new Date().toISOString()
};

// Attach metadata to Stripe payable object
const stripeResponse = $input.first().json;
const webhookData = $('CRM Action: Send Payment').first().json;

// Extract metadata from webhook body
const metadata = {
  contactId: webhookData.body?.contactId || webhookData.contactId || '',
  invoiceId: webhookData.body?.invoiceId || webhookData.invoiceId || '',
  tenantId: webhookData.body?.tenantId || webhookData.tenantId || '',
  createdAt: new Date().toISOString(),
  source: 'crm_payment_request'
};

// Merge Stripe response with metadata
const result = {
  ...stripeResponse,
  metadata: metadata,
  stripeCustomerId: stripeResponse.customer || stripeResponse.id || '',
  stripePaymentId: stripeResponse.id || stripeResponse.payment_intent || '',
  paymentUrl: stripeResponse.url || stripeResponse.hosted_invoice_url || ''
};

return result;

// Add WhatsApp prefix to phone numbers from webhook payload
const item = $input.item.json;

// Extract phone numbers from webhook body
const fromNumber = item.body?.from || item.from || '';
const toNumber = item.body?.to || item.to || '';

// Add whatsapp: prefix to numbers
const whatsappFrom = fromNumber.startsWith('whatsapp:') ? fromNumber : `whatsapp:${fromNumber}`;
const whatsappTo = toNumber.startsWith('whatsapp:') ? toNumber : `whatsapp:${toNumber}`;

return {
  ...item,
  from: whatsappFrom,
  to: whatsappTo,
  originalFrom: fromNumber,
  originalTo: toNumber
};

// Parse Twilio WhatsApp webhook payload
const item = $input.first().json;

// Extract fields from Twilio webhook (can be in body or query)
const payload = item.body || item.query || item;

// Extract phone numbers and strip 'whatsapp:' prefix
const fromRaw = payload.From || '';
const toRaw = payload.To || '';

// Remove 'whatsapp:' prefix if present
const from = fromRaw.replace(/^whatsapp:/, '');
const to = toRaw.replace(/^whatsapp:/, '');

// Extract message body
const body = payload.Body || '';

// Extract message SID
const messageSid = payload.MessageSid || payload.SmsMessageSid || '';

// Extract media fields (Twilio can send multiple media attachments)
const numMedia = parseInt(payload.NumMedia) || 0;
const media = [];

for (let i = 0; i < numMedia; i++) {
  const mediaUrl = payload[`MediaUrl${i}`] || '';
  const mediaContentType = payload[`MediaContentType${i}`] || '';

  if (mediaUrl) {
    media.push({
      url: mediaUrl,
      contentType: mediaContentType
    });
  }
}

// Return parsed data
return {
  from: from,
  to: to,
  body: body,
  messageSid: messageSid,
  media: media,
  numMedia: numMedia,
  timestamp: new Date().toISOString(),
  rawPayload: payload
};

